-- 0154_feature_map.sql
-- In-app Feature Map: an admin-curated catalog of what the app can do, rendered
-- inside the app on a dedicated screen. Admin-only for now (entry point gated in
-- Settings), but the data is world-readable for signed-in users so it can be
-- opened up to everyone later without a schema change. One row per feature card.
--
-- Reads: any authenticated user. Writes: admin only, via the same
-- auth.email() gate every other admin surface uses. No dedicated RPC, the admin
-- screen does plain authenticated INSERT/UPDATE/DELETE that RLS restricts.

CREATE TABLE IF NOT EXISTS public.zane_feature_map (
  id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  cat         text        NOT NULL,
  name        text        NOT NULL,
  role        text        NOT NULL DEFAULT 'user' CHECK (role IN ('user','coach','both')),
  summary     text        NOT NULL DEFAULT '',
  actions     jsonb       NOT NULL DEFAULT '[]'::jsonb,
  sort        int         NOT NULL DEFAULT 0,
  created_at  timestamptz NOT NULL DEFAULT now(),
  updated_at  timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_zane_feature_map_cat_sort ON public.zane_feature_map (cat, sort);

ALTER TABLE public.zane_feature_map ENABLE ROW LEVEL SECURITY;

-- Everyone signed in can read the map.
CREATE POLICY "feature_map_read" ON public.zane_feature_map
  FOR SELECT TO authenticated USING (true);

-- Only the admin can create, edit or remove cards.
CREATE POLICY "feature_map_admin_insert" ON public.zane_feature_map
  FOR INSERT TO authenticated
  WITH CHECK ((select auth.email()) = 'office@btc-prime.biz');
CREATE POLICY "feature_map_admin_update" ON public.zane_feature_map
  FOR UPDATE TO authenticated
  USING ((select auth.email()) = 'office@btc-prime.biz')
  WITH CHECK ((select auth.email()) = 'office@btc-prime.biz');
CREATE POLICY "feature_map_admin_delete" ON public.zane_feature_map
  FOR DELETE TO authenticated
  USING ((select auth.email()) = 'office@btc-prime.biz');

-- Seed with the current catalog (156 cards).
