INSERT INTO public.zane_feature_map (cat, name, role, summary, actions, sort) VALUES
('start', 'Sign in', 'user', 'Sign in with your email and password or a passkey, get a heads-up if you are in an in-app browser where login often fails, and sign out again when you are done.', '["Sign in with email and password", "Sign in with a passkey", "Reveal the password with the eye toggle", "See a warning inside in-app browsers", "Sign out on this device"]'::jsonb, 0),
('start', 'Sign up for an account', 'user', 'Create your account with a nickname, email, and password, and pick your units (metric, imperial, or mixed) right from the start.', '["Register with nickname, email, and password", "Confirm the password with a live match check", "Choose metric (kg/km), imperial (lbs/mi), or mixed (kg/mi) units"]'::jsonb, 1),
('start', 'Account approval', 'user', 'After you register, a pending screen keeps you posted while an admin approves your account, then lets you in automatically once you are cleared.', '["See your awaiting-approval status", "Get let in automatically once approved (rechecks when you reopen the app)", "Sign out while you wait"]'::jsonb, 2),
('start', 'Forgot and reset password, invite links', 'user', 'Regain access on your own by requesting a reset link by email, and set a fresh password straight from a reset or invite link.', '["Request a reset link by email from the login screen", "Set a new password from a reset link and log straight back in", "Set your name and password when accepting a coach or admin invite"]'::jsonb, 3),
('start', 'Passkeys (Face ID, Touch ID, PIN)', 'user', 'Sign in with your face, fingerprint, or device PIN instead of typing a password, keeping one passkey per device with your password always available as a fallback.', '["Add a passkey for the current device in Settings", "Sign in with biometrics or your device PIN", "See registered passkeys with the date each was added", "Remove a passkey you no longer use"]'::jsonb, 4),
('start', 'Choose your units', 'user', 'Pick metric (kg/km), imperial (lbs/mi), or a mixed kg/mi setup when you sign up, applied consistently to every weight and distance label and changeable any time in Settings.', '["Choose metric, imperial, or mixed when you sign up", "Have the choice apply to every weight and distance label", "Change your units any time in Settings"]'::jsonb, 5),
('start', 'Your display name', 'user', 'Set the nickname that shows up around the app and to your coach.', '["Type your name in the Nickname field at the top of Settings", "Save it on blur or by pressing Enter", "Have it appear to your coach"]'::jsonb, 6),
('start', 'Change your password or email', 'user', 'Update your login password or email address from inside the app without signing out, with clear success or error feedback.', '["Change your password with a current-password check (minimum six characters)", "Change your email, confirmed by a link sent to the new inbox", "Toggle show/hide to check what you typed"]'::jsonb, 7),
('start', 'Quick account switch', 'user', 'On a shared device, jump between two linked accounts without retyping a password each time.', '["See which account is active", "Tap the other account to switch instantly", "Set it up by signing out so a second person can log in"]'::jsonb, 8),
('start', 'Guided tours and How-to walkthroughs', 'both', 'Interactive walkthroughs spotlight real buttons, move you between screens, and teach every corner of the app hands-on, replayable any time from Settings.', '["Take the welcome tour on first launch or skip it", "Replay any tour from Settings, How to", "Learn plans, workouts, Health, Quick Actions, cardio, status modes, customization, and coaching", "Follow a step counter and finish on a completion screen"]'::jsonb, 9),
('start', 'Install as an app', 'user', 'Add the app to your phone''s home screen for a full-screen, instant-loading experience with reliable notifications, using illustrated steps for iPhone and Android.', '["Follow the iPhone (Safari) install steps", "Follow the Android (Chrome) install steps", "Get a full-screen app with background notifications"]'::jsonb, 10),
('start', 'What''s New and changelog', 'user', 'Catch up on everything added since your last visit in a bundled What''s New card on launch, and browse the full release history any time.', '["See unseen updates in a What''s New card on launch", "Dismiss it with Got it", "Open the full changelog in Settings", "Drill into older releases grouped by week and year and read their notes"]'::jsonb, 11),
('start', 'In-app update prompt', 'user', 'When a new version is ready, a one-tap prompt installs it, and it politely waits until your live workout is finished before interrupting.', '["Tap Update Now to install the latest version", "Keep training uninterrupted while an update waits out your session"]'::jsonb, 12),
('start', 'Friendly error recovery', 'user', 'If a screen hits an error or your data cannot load, you get a clear message and a one-tap way back to Home or to try again.', '["Tap Back to Home after a screen error", "Retry loading when data fails to load"]'::jsonb, 13),
('start', 'Support Center', 'user', 'Open support tickets and chat with the team about bugs, feature ideas, or questions, and track each one through to resolution.', '["Create a ticket tagged Feature request, Bug, or General question", "Attach or paste a screenshot", "Message in a threaded conversation with read status", "Track status (open, in progress, resolved) and browse a resolved-ticket archive"]'::jsonb, 14),
('home', 'App navigation', 'both', 'Move between the app''s main sections from a bottom tab bar (a side rail on iPad), with Health and Coaching tabs that appear only when you use them.', '["Switch between Home, Plan, History, Health, and Coaching", "Reach the exercise Library and Cardio plans under the Plan tab", "Show or hide the Health and Coaching tabs", "See a coaching badge for unread notes, pending check-ins, and live clients", "Jump back to Home from anywhere"]'::jsonb, 0),
('home', 'Home header & sync status', 'user', 'The home header greets you by name with today''s date and opens Settings, while a small dumbbell icon shows whether your data is saved, still saving, or failed to sync so you can tap to retry.', '["See your name and today''s date at the top", "Open Settings from the gear button", "Check your save and sync status at a glance", "Tap the sync icon to retry a failed save"]'::jsonb, 1),
('home', 'Week & cycle navigation', 'user', 'Step backward and forward through your training weeks or plan cycles with a clear label of where you are (This Week, Cycle 3, Deload, or your mesocycle position), including your current mesocycle week and RIR target.', '["Browse other weeks or cycles with the back and forward arrows", "Read the period label (This Week, Cycle X, Deload, Flexible)", "See your mesocycle week counter and RIR target"]'::jsonb, 2),
('home', 'Day strip', 'user', 'A row of day tiles lays out your plan''s week at a glance, marking each day as completed, missed, skipped, a rest day, or a sick/vacation day with today highlighted, and tapping any tile previews that day''s workout.', '["Tap a day tile to select and preview it", "See completed, missed, skipped, and rest days marked", "Spot sick and vacation days by their icon", "See cycle boundaries in the cycle-week view"]'::jsonb, 3),
('home', 'Today''s workout, start & resume', 'user', 'The main card shows the selected day''s workout in large type with quick stats (exercise count, estimated or average duration, total sets) and a scrollable exercise list, and one prominent button starts or logs the session; if a workout is already underway, a gold banner lets you jump back in or discard it.', '["Read the day''s exercises, estimated minutes, and set count", "Tap Start Workout, or log a past or future day", "Catch up a day on a flexible plan", "Resume an in-progress session from the active banner", "Cancel an in-progress session to discard it"]'::jsonb, 4),
('home', 'Skip a training day', 'user', 'Mark a planned day as skipped and record why (Tired, Sick, Stress, Forgot, Rest, or no particular reason); on flexible plans a skip simply advances the rotation, and you can edit or remove a skip later to make the day loggable again.', '["Skip today''s planned day from its card", "Pick a reason for the skip", "Edit the reason on an already-skipped day", "Delete a skip to make the day loggable again"]'::jsonb, 5),
('home', 'Rest & recovery day card', 'user', 'On rest days the card shows a recovery message (or a Sick/Away message when a status is active) with a shortcut to view your plan, and lets you clear a sick or vacation status to return to normal training.', '["See your recovery, sick, or away message", "View your plan from the rest card", "Tap Back to normal to clear a sick or vacation status"]'::jsonb, 6),
('home', 'Review a completed workout', 'user', 'After a workout, its card and a recent-session strip show when you trained, the total volume you lifted, and how many lifts improved or regressed versus last time, and either one opens the full session detail.', '["See the date, time, and total volume of a finished workout", "See how many lifts improved or regressed versus last time", "Tap to open the full completed session"]'::jsonb, 7),
('home', 'Log a missed or past session', 'user', 'Home flags recent planned days you never logged with a red reminder and gathers all outstanding days into a backlog, so you can retroactively log any of them or dismiss the ones you skipped.', '["See recent unlogged days flagged in red", "Log a missed session after the fact", "Pick which outstanding day to log from the backlog", "Dismiss a missed day you do not want to log"]'::jsonb, 8),
('home', 'Quick Actions menu', 'user', 'Pull down or tap the chevron under the header to open Quick Actions, a shortcut hub for logging the day, starting a workout, logging cardio, catching up missed sessions, doing a check-in, messaging your coach, or reloading the app.', '["Open Quick Actions by pulling down or tapping the chevron", "Jump to Daily Log, Workout, Cardio, or Backlog", "Open a due check-in or message your coach", "Reload the app to clear cache and refetch data"]'::jsonb, 9),
('home', 'Today''s cardio on the home screen', 'user', 'When you have an active cardio plan, a card on the home screen shows today''s target and logs the session in one tap.', '["See today''s planned distance, duration and pace (or a free session) for your active plan", "Tap to log the session, pre-filled with the planned distance and duration", "See a done state with a summary once the session is complete"]'::jsonb, 10),
('plans', 'Plan list & overview', 'user', 'Browse all your training plans in one place, with your active plan pinned to the top and each card showing its day types and where it stands.', '["Open the Plan tab to see every plan", "Spot the active plan by its highlight and badge", "Read each plan''s summary line: cycle length, training days or workouts per week", "See day-type chips like PUSH, PULL, LEGS at a glance", "See status badges for mesocycle, 5/3/1 cycle and week, and version"]'::jsonb, 0),
('plans', 'Manage your plans', 'user', 'Keep several plans and switch between them cleanly, activating the one that drives your sessions and tidying away the rest.', '["Activate a plan so it drives your workouts (cycle resets to day one)", "Duplicate a plan into an editable copy to experiment safely", "Archive a plan to hide it without deleting it, then unarchive later", "Browse the collapsible Archived section", "Delete a plan permanently"]'::jsonb, 1),
('plans', 'Start a new plan', 'user', 'Create a new plan from whichever starting point suits you (a self-progressing program, a ready-made split, or a blank custom build) with a step-by-step wizard walking you through the setup.', '["Tap the + button to start a new plan", "Choose Programs, Templates or Custom as your starting point", "Name your plan and move through the guided steps with a progress bar", "Skip the walkthrough for an empty plan, or discard before creating"]'::jsonb, 2),
('plans', 'Choose how the plan advances', 'user', 'Decide how your plan moves forward in time so it fits how you actually train, from a strict calendar rotation to a flexible one that never falls out of sync.', '["Pick Cycle: a repeating rotation that advances by date and includes rest days", "Pick Weekdays: fixed days like Mon, Wed, Fri", "Pick Flexible: advances only when you train or skip, never by the calendar", "Set an optional weekly training goal used for adherence and deload timing"]'::jsonb, 3),
('plans', 'Training split presets', 'user', 'Pick a proven split and the app lays out the days for you, or go custom and choose your own number of training days.', '["Choose Full Body, Upper/Lower, Push/Pull/Legs or PPL x2", "Choose Custom and set the number of days with a stepper", "See a frequency hint for your chosen day count"]'::jsonb, 4),
('plans', 'Set up your training days', 'user', 'Define what each day in your plan is, either by tapping the weekdays you train or by setting a type for every day, with a running overview so the structure stays clear.', '["Tap the weekdays you train on a Mon to Sun grid", "Set each day''s type: push, pull, legs, upper, lower, full, arms, back or rest", "Get warned if a fixed split needs an exact number of training days", "Watch a ''plan so far'' overview build as you go"]'::jsonb, 5),
('plans', 'Custom day types', 'user', 'Create your own day labels like PUSH1 and PUSH2 so plans with repeated variants read clearly, then reuse or remove them across plans.', '["Create a custom day type by name", "Reuse your saved custom types across plans", "Delete a custom day type (existing plans keep their names)"]'::jsonb, 6),
('plans', 'Import a training day', 'user', 'Pull a whole day, its exercises and even its history, from another plan or a saved template instead of rebuilding it from scratch.', '["Import a day from any plan or template", "Pick several days at once to fill the following slots", "Choose which weekday it lands on for weekday plans", "Carry over the day''s training history on import"]'::jsonb, 7),
('plans', 'Mesocycle blocks & autoregulation', 'user', 'Turn any plan into a fixed 4 to 8 week block with a planned effort ramp and an end-of-block deload, and let the app auto-tune your volume and loads from the feedback you give while training.', '["Choose a fixed block and set its length (4 to 8 weeks)", "Set the RIR taper from a start value to an end value", "Use negative RIR (Hell Mode) for automatic partials past failure", "Earn weight boosts that compound across blocks", "Get an automatic deload offer when the block ends", "Read the explainer or reset your mesocycle history"]'::jsonb, 8),
('plans', 'Prebuilt program templates', 'user', 'Start from a proven split matched to how many days a week you train, previewing it in full before you commit.', '["Browse templates by days per week (2 to 6)", "Read each template''s blurb and day list", "Preview the whole split with its planned sets and reps", "Use it as is, or open it as a new plan to edit"]'::jsonb, 9),
('plans', 'Wendler 5/3/1 program', 'user', 'Set up Wendler''s 5/3/1 with a Training Max per lift and let it calculate every working weight, wave 5s/3s/1s across the cycle, and progress your Maxes automatically.', '["Set a Training Max per lift, or estimate it from your logged history", "Toggle assistance work and the light deload week on or off", "Add extra main lifts beyond the classic four and classify them upper or lower", "Edit a Training Max by hand or snap it back to what your history implies", "Do the AMRAP top set and watch weights auto-bump each cycle"]'::jsonb, 10),
('plans', '5/3/1 progress tracking', 'user', 'See how your 5/3/1 is progressing at a glance: your current cycle and week, plus how each lift''s Training Max has climbed across cycles.', '["Open the 5/3/1 progress view", "See your current cycle and week", "See each lift''s Training Max and its total change", "Read a Training Max chart across cycles with reset points marked"]'::jsonb, 11),
('plans', 'Plan viewer (day by day)', 'user', 'Open any plan read-only and step through its days to see exactly the weights and reps that will pre-fill when you train, including smart-progression bumps and superset grouping.', '["Switch days with chips or a tablet sidebar", "Spot today''s day with a TODAY marker", "See pre-filled weight and reps per set, with an up-arrow for a progression bump", "See rest days as a recovery card and superset or giant-set grouping"]'::jsonb, 12),
('plans', 'Export & import plans', 'user', 'Save a plan with its exercises and settings to a file you can share, and import a plan file someone sent you, reusing your existing exercises by name.', '["Export a plan to a file", "Import a plan from a file", "Reuse matching library exercises by name on import"]'::jsonb, 13),
('plans', 'Automatic plan backups', 'user', 'Every time you change your training days the app snapshots them (up to 10 per plan) so you can preview an old version and roll back if a change did not work out.', '["Open the Backups list of recent snapshots", "Preview any snapshot day by day", "Restore a snapshot, replacing your current days", "For versioned plans, restore from a chosen date and starting day"]'::jsonb, 14),
('plans', 'Plan versioning & scheduled changes', 'user', 'Apply plan changes from a date you choose so your split keeps a browsable history of past, current and upcoming versions, and mid-plan edits never disrupt where you are.', '["Save small edits immediately, or apply structural changes from a future date", "Choose which day the new structure starts on", "Step through versions and see each one''s status and effective dates", "Reactivate or edit a past version, or fix its start date"]'::jsonb, 15),
('plans', 'Plan editor: days & structure', 'user', 'Reshape a plan freely by adding, removing, renaming and reordering its days, switching between a repeating cycle and fixed weekdays.', '["Rename the plan and switch between Cycle and Weekdays mode", "Add a day and choose its type", "Long-press and drag days to reorder them", "Remove a day, with a confirm if it holds exercises", "Toggle training weekdays on or off for a weekday plan"]'::jsonb, 16),
('plans', 'Cycle / week start date', 'user', 'Anchor an active plan to the calendar by setting when Day 1 or Week 1 lands, and see which day or week today maps to.', '["Set the cycle start date (Day 1) for a cycle plan", "Set the week start date (Week 1) for a weekday plan", "See where today falls, like ''Day 3 of 6'' or ''Week 2''"]'::jsonb, 17),
('plans', 'Day editor: build a training day', 'user', 'Fill a day with exercises and shape how they flow: add movements, reorder them, remove them, and link them into supersets or giant sets.', '["Set the day''s type", "Add exercises to the day", "Long-press and drag to reorder exercises", "Remove an exercise", "Link exercises into supersets or giant sets, or unlink", "Import exercises from another plan or template"]'::jsonb, 18),
('plans', 'Exercise picker', 'user', 'Find and add exercises while building a day: search, filter by muscle, add several at once, or create a brand-new movement on the spot.', '["Search exercises by name or tag", "Filter by muscle-group pills", "Multi-select several exercises to add at once", "Pull from the built-in movement database", "Create a new exercise inline if none fits"]'::jsonb, 19),
('plans', 'Configure sets, reps & progression per exercise', 'user', 'Dial in exactly how each exercise is programmed: its number of sets, a rep scheme, whether smart weight progression applies, and a cue note that follows the exercise everywhere.', '["Set the number of sets", "Choose Uniform, Range or Per-Set reps", "Override smart progression per exercise (custom rep ceiling or off), or inherit the global default", "Attach a note or cue that shows whenever you train the exercise"]'::jsonb, 20),
('plans', 'Notify coach of plan changes', 'both', 'When you edit an active plan your coach shares, a summary of what changed is sent to them automatically so they always know your current programming.', '["Auto-send a plan-change summary to your coach on save", "Keep a shared plan''s edits visible to your coach without messaging them"]'::jsonb, 21),
('plans', 'Deload week', 'user', 'Run a lighter recovery week at about 50% load straight from your active plan, with weights pre-filled light, progression paused, and training resuming right where it left off.', '["Start a deload from the active plan card", "Get nudged toward one after several completed cycles or weeks", "See days remaining while it is active", "End it, or let it auto-end, and pick up exactly where you paused", "Start a deload that replaces a sick or vacation status"]'::jsonb, 22),
('plans', 'Milestones and mesocycle transitions', 'user', 'At key milestones the app congratulates you and offers the right next step, from a deload to starting a fresh training block.', '["Get a deload offer after 8 cycles, weeks or sessions", "See your 5/3/1 Training Max increases at the end of a cycle", "Start the next mesocycle, continue as a cycle, or deactivate the plan"]'::jsonb, 23),
('plans', 'Return-from-break realign', 'user', 'After you end a sick or vacation break on a rotating plan, a welcome-back sheet lets you choose where to pick the rotation back up.', '["Choose which plan day to resume on after a break", "Or restart the rotation from day one"]'::jsonb, 24),
('plans', 'Workout templates', 'user', 'Save any workout as a reusable template, then use it to start a fresh session or seed a day in your plan.', '["Save a freestyle session as a template", "Start a workout from a template", "Drop a template into a plan day", "Delete templates from the Templates tab"]'::jsonb, 25),
('logging', 'Auto-ended workout notice', 'user', 'If you forget to end a workout, the app closes it for you and shows a banner naming the session and how long was recorded.', '["See which workout was auto-ended and its recorded duration", "Dismiss the notice"]'::jsonb, 0),
('logging', 'Warmup ramp prompt', 'user', 'Before a weighted session a sheet previews a 30/60/100% warmup ramp built from your first working weight and lets you start with those warmup sets added or skip straight to your working sets.', '["Preview the suggested 30/60/100% warmup sets and reps", "Start with the warmup sets prepended", "Skip warmups and go straight to working sets"]'::jsonb, 1),
('logging', 'In-session recovery check-ins', 'user', 'During a mesocycle the app asks quick recovery questions so it can auto-tune your training, and your answers stay editable until you finish the session.', '["Rate soreness per muscle, from never sore to still sore", "Flag joint discomfort per exercise (none, noticeable or sharp)", "Rate pump and whether the volume felt right", "Reopen the recap to review and revise answers by muscle group"]'::jsonb, 2),
('logging', 'Next-session auto-adjustments', 'user', 'After you submit your feedback, the app shows exactly how your next session will change so autoregulation never happens behind your back.', '["See per-exercise set changes for next time", "See per-exercise weight changes for next time", "Review the adjustments before continuing"]'::jsonb, 3),
('logging', 'RIR target & mesocycle status', 'user', 'Your prescribed reps-in-reserve target sits right on the set alongside where you are in the block, so you always know how hard to push today.', '["See the RIR target watermarked on the current set", "See a deload badge on deload days", "See your current mesocycle week or cycle number", "Notice the set catch fire when the block prescribes training past failure"]'::jsonb, 4),
('logging', 'Start a workout', 'user', 'Begin training however the day calls for it: your scheduled session, any plan day as a bonus, or a blank freestyle session built from scratch or a saved template.', '["Start today''s scheduled session", "Start any plan day as a bonus session", "Start an empty freestyle session, or from a saved template", "Delete a saved workout template", "See each day''s exercise count before you pick"]'::jsonb, 5),
('logging', 'Log weight and reps', 'user', 'Enter the weight and reps for every set on a big, focused card using a purpose-built lifting keypad, with values and references pulled from your history.', '["Type weight and reps on a lifting-specific number pad", "See a last-time reference and your target reps above the inputs", "Nudge a value up or down by one plate step", "Auto fill a weight down to the remaining sets, or override any one", "Add or remove working sets during the exercise", "Check off a set, or check all remaining sets at once"]'::jsonb, 6),
('logging', 'Plate calculator', 'user', 'See exactly which plates go on the bar for any weight, using only the plates you actually own.', '["Open it from the weight keypad", "See the per-side plate breakdown for the load", "Works in kg and lbs"]'::jsonb, 7),
('logging', 'Timed exercises', 'user', 'Run any hold, carry or interval on the clock with a full-screen countdown instead of logging reps.', '["Set a target duration with quick steppers", "Launch a full-screen countdown that beeps down", "Let it auto-complete at zero, or tap Stop to log the actual hold"]'::jsonb, 8),
('logging', 'Specialty exercise logging', 'user', 'Track movements that do not fit the standard weight-and-reps mold, from calisthenics to single-side work.', '["Log reps only for bodyweight moves, with your logged bodyweight used as the load", "Log assisted lifts as negative load, so less help counts as a new best", "Enter left and right sides separately for single-arm or single-leg work", "Tick a checkbox to complete mobility or no-count sets"]'::jsonb, 9),
('logging', 'Rest timer', 'user', 'An automatic countdown starts between sets, sized to the exercise, and can ping you when it runs out.', '["Start a rest countdown automatically after each set", "Watch it in the top bar, tap to open the full rest screen", "Add or subtract 30 seconds, or skip the rest", "Get a push alert when rest is over", "Set default, big, medium and small rest lengths"]'::jsonb, 10),
('logging', 'Guided warmup sets', 'user', 'A warmup overlay walks you through each ramp set at a percentage of your working weight before you start the real work.', '["Follow ramp sets shown as a percent of working weight", "Check off each warmup, or skip straight to working sets", "Warmups stay out of your volume totals", "Choose whether warmups appear in the summary"]'::jsonb, 11),
('logging', 'Session clock and pace bar', 'user', 'A live timer runs the whole workout while a pace bar tells you if you are ahead of or behind your last time at the same point.', '["Watch elapsed session time in the header", "See how many minutes ahead or behind you are versus last time"]'::jsonb, 12),
('logging', 'Rep tempo pacer (Paceguard)', 'user', 'An optional metronome beeps out your lowering and lifting tempo so every rep stays controlled.', '["Turn on the tempo metronome for an exercise", "Set the lowering (eccentric) and lifting (concentric) seconds", "Hear beeps that subdivide each phase"]'::jsonb, 13),
('logging', 'Intensity techniques', 'user', 'Push past failure with one tap using built-in advanced set styles, no manual math or workarounds.', '["Drop sets: descend the weight and keep repping", "Myo-reps and myo-match: rest-pause mini sets to a target", "Lengthened partials: count partial reps past full range", "AMRAP variations: back-to-back max-rep rounds, optional grip swap", "Every technique shows in your summary and history"]'::jsonb, 14),
('logging', 'Supersets and giant sets', 'user', 'Pair or group exercises on the fly so they rotate with no rest between them, right in the middle of a workout.', '["Pair the current exercise with another (existing or brand new)", "Add a third exercise to build a giant set", "See linked exercises joined in the chip strip", "Save the grouping back to your plan"]'::jsonb, 15),
('logging', 'Navigate between exercises', 'user', 'Jump around your session freely and reorder exercises as you go using the chip strip and footer arrows.', '["Tap a chip to jump to any exercise", "Use back and next arrows to move through the session", "Long-press and drag chips to reorder exercises", "See finished exercises marked with a dot"]'::jsonb, 16),
('logging', 'Swap, add or remove exercises mid-session', 'user', 'Adapt your lineup while training by replacing, inserting or dropping exercises without breaking the session.', '["Swap the current exercise for a different one", "Add another exercise, solo or as a superset partner", "Remove an exercise you are not doing", "New exercises seed their sets from your history"]'::jsonb, 17),
('logging', 'Skip sets, exercises or rest', 'user', 'Bail out of remaining work whenever you need to, without leaving the session in a messy state.', '["Finish an exercise early by skipping its remaining sets", "Skip the current rest or warmup", "Skip a cardio entry"]'::jsonb, 18),
('logging', 'Session and exercise notes', 'user', 'Jot a note that lives only on today''s workout, or a permanent cue that shows every time you train that exercise, with the demo video right there too.', '["Add a session note about how a set or the day felt (today only)", "Add a permanent exercise note for form cues", "Edit any note later", "Watch the exercise''s linked demo video while you train"]'::jsonb, 19),
('logging', 'Mesocycle session feedback', 'user', 'Quick per-exercise feedback during a mesocycle auto-tunes your future volume, and you can revisit your answers before finishing.', '["Rate soreness, joints, pump and volume per exercise", "Confirm your answers, with a chance to reconsider", "Revisit and change any answer before finishing", "Your feedback adjusts future volume automatically"]'::jsonb, 20),
('logging', 'Smart progression', 'user', 'Let the app bump your weight automatically once you clear the top of your rep range on every set.', '["Turn on automatic weight increases", "Set how many reps above target trigger the bump", "Treat the shown reps as minimums to always beat"]'::jsonb, 21),
('logging', 'Live PR and progress celebrations', 'user', 'The screen celebrates the moment you beat a previous performance and gives honest cues when a lift slips.', '["See New Best and Personal Record overlays as you log", "Get Improvement and Progression Unlocked cues", "Notice a screen flash on an all-time best", "Hide the regression indicator if you prefer"]'::jsonb, 22),
('logging', 'Outlier safety check', 'user', 'If you enter a weight or rep count that looks off versus what was expected, the app double-checks before saving it.', '["Get a prompt when a number looks unusual", "Confirm to log it anyway", "Or go back and fix the entry"]'::jsonb, 23),
('logging', 'Finish and summary', 'user', 'Ending a session gives you a wrap-up of what you did plus a few quick choices before it is saved.', '["Review incomplete sets, total sets, volume, duration and improvements", "Add another exercise instead of finishing", "Choose whether the session replaces today''s scheduled day or counts as extra", "Name a freestyle session and save it as a reusable template"]'::jsonb, 24),
('logging', 'Rate workout effort', 'user', 'Capture how hard a session felt on a five-level scale so your log reflects effort, not just numbers.', '["Rate effort from Easy to Max on the finish screen", "Skip the rating if you would rather not", "Add or change the rating later from any past session", "View an effort trend chart for each day type"]'::jsonb, 25),
('logging', 'Push workout changes back to your plan', 'user', 'If you changed exercises, set counts, order or supersets during the workout, you can save those edits back into your plan on finish.', '["See every change versus the plan (swaps, set counts, order, supersets)", "Tap Update plan to save them", "Or leave the plan unchanged"]'::jsonb, 26),
('logging', 'Cancel or leave a session', 'user', 'Back out of a live session cleanly, either discarding it or stepping away while keeping your progress.', '["Cancel and discard the session (with a confirm)", "Leave the session while keeping your progress", "Watch a live sync status dot, tap to retry if saving fails"]'::jsonb, 27),
('library', 'Exercise library hub with Recent, My exercises and Database tabs', 'user', 'A central Exercises screen that switches between your recently trained lifts, your full personal list, and a built-in catalog, so every movement lives in one place.', '["Switch between the Recent, My exercises and Database tabs", "See recently trained lifts with days-since, last top set and an up, down or flat trend arrow", "Jump across to the Workout and Cardio sub-tabs", "Tap any exercise to open its detail and history", "Tap the plus button to add a new exercise"]'::jsonb, 0),
('library', 'Search and filter exercises', 'user', 'Find any movement fast by searching names and muscle tags or narrowing the list with a multi-filter sheet, across both your own list and the catalog.', '["Search by exercise name or muscle", "Filter by muscle group, rest size, movement type and equipment", "Filter by whether an exercise is used in a plan or not", "See how many filters are active and clear them all", "Apply search and filters to your own list or the Database"]'::jsonb, 1),
('library', 'Built-in exercise catalog', 'user', 'Browse a curated catalog of around 180 classic strength and hypertrophy movements grouped by muscle, then pull the ones you want into your own library instead of typing them from scratch.', '["Browse and search around 180 common exercises grouped by muscle", "See each entry''s muscles, size, movement and equipment at a glance", "Spot an ''In library'' marker for catalog moves you already own", "Tap Check & Add to review a pre-filled sheet and tweak any field", "Save it as your own editable copy, ready to drop into plans"]'::jsonb, 2),
('library', 'Create a custom exercise with a guided wizard', 'user', 'A step-by-step wizard walks you through building any exercise from scratch with plain-language explainers and a final review before it is saved.', '["Name the exercise and pick its muscle groups", "Choose an exercise size, equipment and movement type", "Pick how each set is logged", "Add a setup note and a form-video link", "Skip a step, go back, or review everything before creating"]'::jsonb, 3),
('library', 'Edit, bulk-edit and delete exercises', 'user', 'Change any field on an exercise from its detail screen, or use Select mode to edit several back-to-back or delete a batch at once, with past workout history always kept.', '["Edit name, muscles, size, equipment, movement, logging, note and video", "Delete a single exercise with a confirmation", "Enter Select mode and pick multiple exercises (Select All or None)", "Edit selected exercises one after another in a queue", "Delete several exercises at once"]'::jsonb, 4),
('library', 'Muscle group tagging', 'user', 'Tag each exercise with the muscles it trains so those sets automatically feed your weekly sets-per-muscle counts.', '["Select one or more muscle groups per exercise", "Choose from Abs, Back, Biceps, Chest, Glutes, Quads, Shoulders and more", "Pre-fill the muscle from an active library filter when creating", "Feed your weekly volume-per-muscle tracking"]'::jsonb, 5),
('library', 'Exercise size and rest-timer link', 'user', 'Mark an exercise as Big, Medium or Small to control which rest-timer preset it uses, so heavier lifts automatically get longer rest.', '["Set an exercise as Big, Medium or Small", "See the actual rest time each size gives you", "Tap the help icon for examples of each size", "Leave size unset if you prefer"]'::jsonb, 6),
('library', 'Equipment type', 'user', 'Tell each exercise what it is loaded with (none, bodyweight, dumbbell, cable, machine, single or dual plates), which also decides how weight is entered while training.', '["Pick an equipment type per exercise", "Change how weight is entered during a workout", "Leave equipment unspecified"]'::jsonb, 7),
('library', 'Movement type and per-set logging mode', 'user', 'Set whether an exercise is logged as one number or one per side and what you record each set (weight and reps, reps only, a timer, or just a tick), covering assisted and mobility work too.', '["Set bilateral (one number) or unilateral (log left and right separately)", "Set assisted lifts to log as a negative band or machine-assisted load", "Set mobility moves for stretches or warm-ups with no load", "Choose a logging mode: Weight & Reps, Reps only, Time or Checkbox", "Get a sensible default picked automatically"]'::jsonb, 8),
('library', 'Auto-pull bodyweight from Health', 'user', 'For weighted bodyweight exercises, have the app fill in your latest logged bodyweight automatically so those sets count toward volume without retyping it every session.', '["Toggle between ''Use my bodyweight'' and entering it manually", "Auto-pull your latest weight from the Health tab", "See a reminder to log your weight if none exists yet"]'::jsonb, 9),
('library', 'Exercise notes and form videos', 'user', 'Attach a free-text note (grip, cues, cable position) and a YouTube form-video link to any exercise, then read the note and watch the video from its detail screen or mid-workout.', '["Write a personal setup or technique note", "Paste a YouTube form-video URL", "Watch the form video from the detail screen or during a session"]'::jsonb, 10),
('library', 'Exercise detail: records, charts and history', 'user', 'Each exercise has a detail page with its personal records, a progress chart and a session-by-session history you can tap into.', '["See PRs tuned to the exercise: best estimated 1RM, best load, best time or best reps, plus sessions and volume", "View a progress chart of your best value over time, toggling weight against reps", "See a separate progression line per working set across sessions", "Scroll every past session with its sets and PR badges, including drop-set, myo-rep and AMRAP rounds", "Tap a history row to open that full session"]'::jsonb, 11),
('progress', 'Exercise history and PRs at a glance', 'user', 'Tap an exercise name mid-workout to see your recent sessions for it, with your best sets and records flagged.', '["Open history to view your recent sessions of an exercise", "See each session''s sets with the best set highlighted", "Spot PR badges on record sessions"]'::jsonb, 0),
('progress', 'Compare sessions', 'user', 'Line up a workout set by set against a past session of the same day to see exactly where you improved.', '["Open a set-by-set comparison right after finishing", "Compare any session from your history", "It auto-matches your most recent earlier session of that day"]'::jsonb, 1),
('progress', 'Workout & cardio history', 'user', 'Browse a complete log of every workout and cardio session you have done, and open any one to see its full set-by-set detail.', '["Switch between workout and cardio history tabs", "Open any session to see every set, rep and weight", "Filter by plan, cycle or week number", "Filter by training day type like Push, Pull or Legs", "Clear all filters at once"]'::jsonb, 2),
('progress', 'Edit or delete a past workout', 'user', 'Fix any finished session after the fact by correcting the numbers, adjusting its date or duration, or removing it entirely if it was logged by mistake.', '["Change the weight or reps of any logged set", "Skip or un-skip individual sets", "Change the workout''s date", "Adjust the recorded duration", "Delete the session (its attached cardio goes too)"]'::jsonb, 3),
('progress', 'Training stats and streaks', 'user', 'See the shape of your training over time: weekly volume, muscle balance, consistency, streaks and your standout sessions at a glance.', '["View weekly sets per muscle and your 8-week volume trend", "See all-time sessions, average volume and duration, and total time trained", "Track current and longest streaks (rest and sick or away days stay neutral)", "See sessions per week, month and year", "Review missed workouts and your best-ever session"]'::jsonb, 4),
('progress', 'Share a workout as an image', 'user', 'Turn any finished session into a clean, watermarked image showing the day, your sets and any personal records, ready to save or share.', '["Generate a shareable picture from any session", "Share it through your phone''s share sheet", "Save it straight to your photos"]'::jsonb, 5),
('health', 'Daily log', 'user', 'Record your whole day in one sheet: bodyweight, steps, water, and macros, with calories worked out for you and room for notes.', '["Log bodyweight, steps, and water (with one-tap +250 and +500 buttons)", "Enter protein, carbs, and fat, with calories auto-calculated or overridden by hand", "Switch to net carbs and add a fiber value to compute them live", "Add a day note plus an off-plan note that carries into your coach check-in", "Log up to 14 days back, and edit or delete any day later"]'::jsonb, 0),
('health', 'Macro targets', 'user', 'Set your own protein, carbs, and fat goals, split between training and rest days, to score how closely you hit them each day.', '["Set separate training-day and rest-day macro targets", "See calories computed automatically from your macros", "Start from targets your coach prefilled and adjust them", "Get an adherence rating per day and per period (Perfect, Strong, On Track, Off Track)"]'::jsonb, 1),
('health', 'Coach-requested daily fields', 'user', 'Fill in extra daily metrics your coach has asked you to track, right inside your daily log.', '["Answer the custom fields in the ''Your coach wants to know'' block", "Save those values alongside your normal daily log"]'::jsonb, 2),
('health', 'Blood glucose tracking', 'user', 'Log blood glucose readings any time with context and notes, then spot patterns on a color-coded chart with normal-range bands.', '["Add readings with a value, time, context (fasted, fed, or other), and note", "Edit or delete existing readings", "View readings on a scatter chart with fasting and post-meal reference lines", "Read a feed of readings that carry notes", "Choose your unit (mmol/L or mg/dL) and switch the chart across 1W, 1M, and 3M"]'::jsonb, 3),
('health', 'Sick, Vacation & Deload status', 'user', 'Flag Sick or Vacation days from your daily log so they are not scored and the home screen reflects your state; a Deload status behaves the same way and is started from your training plan.', '["Set Sick or Vacation from the daily log, backdated up to 14 days", "Start a Deload from the deload nudge or your active plan card", "Return to normal and choose which cycle day to resume on", "Skip macro adherence scoring while any status is active", "Get asked to end Sick mode automatically after you next train", "Review, edit, or delete your past status periods"]'::jsonb, 4),
('health', 'Browse and review any day', 'user', 'Move through a week strip to open any past day and see its full picture at a glance: weight, steps, calories, water, macros, adherence, and whether you trained.', '["Tap a day in the Monday-to-Sunday strip, with logged and training days marked", "Open a calendar to jump to any earlier date", "Read the day''s weight, steps, calories, water, macros, and adherence verdict", "See Trained and Cardio badges, and jump back to today", "On a flexible plan, mark the day as Training or Rest to apply the right target"]'::jsonb, 5),
('health', 'Trend charts', 'user', 'Visualize your weight, steps, macros, cardio minutes, and adherence over time, each with a one-week, one-month, or three-month view.', '["View a weight line chart with a rolling average", "View steps and cardio-minute bar charts", "View a stacked macros chart with your daily targets", "View a macro-adherence line chart", "Switch any chart between 1W, 1M, and 3M"]'::jsonb, 6),
('health', 'Period overview', 'user', 'See rolled-up averages and totals for the current week, last 30 days, or last 3 months so you can judge how a stretch of time went.', '["Switch the overview between 1W, 1M, and 3M", "See average macro adherence with a verdict", "See workouts done versus planned", "See averaged weight, steps, cardio, water, calories, and macros"]'::jsonb, 7),
('health', 'Reorderable dashboard cards', 'both', 'Drag the Health cards into whatever order suits you, remembered on that device.', '["Drag a card by its grip handle to reorder", "Keep your custom layout saved per device"]'::jsonb, 8),
('health', 'Export health data', 'user', 'Export your daily logs over any date range as a spreadsheet-ready CSV or a printable PDF report.', '["Pick a range with 7, 30, or 90-day presets or custom From and To dates", "See how many days are logged in the range", "Export CSV with weight, steps, calories, macros, water, adherence, cardio, training, and notes", "Export a styled, printable PDF report for each day"]'::jsonb, 9),
('health', 'Screenshot & share dashboard', 'user', 'Capture your whole Health dashboard as an image to save or share.', '["Tap the camera button in the top bar", "Share the image on mobile or download it on desktop"]'::jsonb, 10),
('health', 'Enable the Health tab', 'user', 'Turn on a dedicated Health tab in the nav bar to log daily nutrition and body metrics and follow your trends.', '["Toggle the Health tab on or off", "Feed your daily logs into your weekly coach check-in automatically"]'::jsonb, 11),
('cardio', 'Log a cardio session', 'user', 'Record any cardio session by hand, capturing the date, activity type (with quick chips for your recent types), duration, distance, how the pace felt, effort, and a note.', '["Enter date, activity type, duration and distance", "Switch distance between km and miles, with pace and speed calculated for you", "Rate how the pace felt (Easy to Max) and effort out of 10", "Add a note to the session", "Edit or delete any logged session", "Add cardio as an exercise inside a training day"]'::jsonb, 0),
('cardio', 'Live cardio stopwatch with guided finish', 'user', 'Start a live timer that keeps counting through phone locks and app reloads, then a friendly finish flow walks you through the details one question at a time.', '["Start a live stopwatch and watch the elapsed time count up", "Keep timing safely through phone locks and reloads", "Finish to a Well done screen, or cancel", "Add type, distance, pace feeling, effort and a note step by step, or save right away", "Discard the session"]'::jsonb, 1),
('cardio', 'Cardio day summary and recent log', 'user', 'On any day with cardio logged, a banner sums up the day (type, minutes, distance, effort), and tapping it opens your recent sessions with quick ways to log more.', '["See a summary of the selected day''s cardio", "Open your recent cardio sessions (last five)", "Edit or delete a logged session", "Start a live timer or log manually from the popover"]'::jsonb, 2),
('cardio', 'Per-activity cardio breakdown', 'user', 'Tap any activity name in your history to open a dedicated view for that activity, with trend charts and lifetime totals so you can tell if your running, cycling or rowing is improving.', '["Open a detail view for any activity type", "See trend charts for duration, speed, distance, effort and pace feeling", "See total sessions, total time and total distance for that activity"]'::jsonb, 3),
('cardio', 'Cardio personal bests', 'user', 'Beat a record and a full-screen gold flash celebrates it, tracking your fastest pace, longest distance and longest session per activity type.', '["See a New Best flash when you set a record", "See an Improvement flash when you beat your last session of the same type", "Compare the new value against your previous best"]'::jsonb, 4),
('cardio', 'Cardio plans tab', 'user', 'A dedicated Cardio tab (alongside Workout and Exercises) holds all your cardio training plans and shows which one is currently active.', '["Switch between the Workout, Exercises and Cardio sub-tabs", "See your active plan highlighted with a badge and the weekdays it trains", "Tap any plan card to open its details", "Start a new plan with the + button, or from the empty-state prompt"]'::jsonb, 5),
('cardio', 'Build a cardio plan (guided wizard)', 'user', 'A step-by-step sheet walks you through creating a cardio plan, from picking the activity to naming it, with Back and Next so you can review each choice.', '["Pick an activity: Running, Walking, Cycling, Swimming, Rowing, Elliptical, Hiking, or a custom type from your history", "Move through the steps with Next and Back and a progress bar", "Accept an auto-suggested plan name or set your own", "Close safely: a confirm dialog protects unsaved setup"]'::jsonb, 6),
('cardio', 'Manual weekly cardio plan', 'user', 'Build a fixed weekly cardio schedule where you choose which days you train and, optionally, a target for each day.', '["Toggle training days Mon to Sun, or select them all at once", "Turn daily targets on to set goals per day, or off to just show up", "Set each target as a distance or a duration", "Use one shared target for every day, or set each day individually"]'::jsonb, 7),
('cardio', 'Goal cardio plan with automatic progression', 'user', 'Set a target and a due date and the app builds a progressive, week-by-week plan that ramps you up to your goal, with lighter recovery weeks built in.', '["Pick a goal type: distance, distance plus pace, or duration", "Enter your target and due date and choose which weekdays you train", "Enter your current baseline (how far or how long you can go comfortably now)", "Generate a full session-by-session plan with an easier recovery week every fourth week", "Preview how the sessions progress, with a warning if the goal is too ambitious for the timeline"]'::jsonb, 8),
('cardio', 'Cardio plan detail view', 'user', 'Open any plan to browse its week, see each day''s target, and track your progress toward a goal.', '["Tap weekday chips to see that day''s target, a rest day, or a free session", "See each target''s distance, duration, pace and speed, with a checkmark when today''s session is logged", "For goal plans, see the goal, due date, progress (session X of Y) and target pace"]'::jsonb, 9),
('cardio', 'Manage cardio plans', 'user', 'Keep one plan active at a time and tidy away the rest across each plan''s full lifecycle.', '["Activate a plan (or deactivate it) so it drives your home screen", "Edit a plan''s activity, days, targets, goal or name", "Archive a plan to hide it, then restore it later", "Delete a plan permanently, with a confirmation prompt"]'::jsonb, 10),
('coachClient', 'Connect with a coach', 'user', 'When a coach invites you, a full-screen request shows who they are and exactly what access it grants (your training, sessions and plans), so you can accept to start working together or decline.', '["See who wants to coach you and what data they will be able to view and adjust", "Accept the invite to start the coaching relationship", "Decline an invite you don''t want"]'::jsonb, 0),
('coachClient', 'See and end your coaching relationship', 'user', 'A ''My Coach'' card shows your coach''s name and email (with a pending badge while an invite is open) and lets you end the relationship and revoke their access at any time.', '["View your coach''s name and email", "See a pending status while an invite awaits your response", "End the relationship and immediately cut off your coach''s access to your data"]'::jsonb, 1),
('coachClient', 'Message your coach', 'both', 'Chat with your coach in tidy topic threads (Nutrition, Goals, Form check and more), sending text and photos both ways, with a home banner and quick shortcut so you never miss a new message.', '["Create named threads, each with its own unread count", "Send text messages and attach or paste photos and screenshots", "Tap any image to view it full-screen", "Jump straight to a conversation from the home banner or a quick shortcut", "Delete a thread (coach)"]'::jsonb, 2),
('coachClient', 'Submit your weekly check-in', 'user', 'Fill in and send the weekly check-in your coach designed for you (bodyweight, recovery, training, cardio, nutrition and notes), with most fields auto-filled from what you already logged that week.', '["Report body weight, plus hunger, sleep, stress and tiredness on a 1 to 10 scale", "Enter days trained, performance versus last week, steps, cardio minutes, distance and pace", "Log calories, protein, carbs, fat, hydration and off-plan days", "Write goals, issues and a general note for your coach", "Let fields pre-fill automatically from your daily logs, cardio and training"]'::jsonb, 3),
('coachClient', 'Preview this week''s check-in early', 'user', 'Before the week is over you can preview your upcoming check-in from the data building up so far, so you can see where you stand mid-week.', '["Tap ''Preview this week'' to see an in-progress check-in", "Watch running totals build up before the week closes", "Submit once the week ends"]'::jsonb, 4),
('coachClient', 'Edit or delete a submitted check-in', 'user', 'Go back and correct or remove a check-in you already sent, with edits logged to your coach so they always see the current numbers.', '["Edit the current or any past check-in", "Delete a check-in submitted by mistake", "Expand your history to review previous check-ins"]'::jsonb, 5),
('coachClient', 'Check-in trends and week-over-week changes', 'both', 'Every check-in metric (weight, sleep, hunger, stress, steps, cardio and more) is charted over up to 20 weeks with up or down arrows versus last week, colored green or red for whether that change is good or bad.', '["View trend charts for each tracked metric", "See week-over-week change arrows on every value", "Spot improving or declining markers at a glance"]'::jsonb, 6),
('coachClient', 'View coach-set macros', 'user', 'See the training-day and rest-day nutrition targets your coach has prescribed, so you always know what to eat.', '["View training-day and rest-day calories, protein, carbs and fat", "See when the targets were last updated"]'::jsonb, 7),
('coachClient', 'Check-in reminders and requests', 'user', 'The app tells you when a check-in is due, surfaces a shortcut straight to it, and posts a note in your check-in thread whenever your coach pauses or re-enables check-ins.', '["See when this week''s check-in is due and jump straight to it", "Choose which check-in to open when you have both a coach and self-coaching", "Get a prompt when your coach requests your check-in, and dismiss it for the day", "Be notified when your coach pauses or resumes your check-ins"]'::jsonb, 8),
('coachClient', 'Be your own coach', 'user', 'Self-coaching points the full coaching toolbox at your own training, so you can review your progress dashboards and run weekly check-ins on yourself for accountability, no coach needed.', '["Enable self-coaching in Settings", "Review your own overview, sessions, plan and health dashboards", "Build and customize your own weekly check-in form and templates", "Submit weekly check-ins to yourself and track your trends and macros"]'::jsonb, 9),
('coachClient', 'Switch between coaching roles', 'both', 'If you are a coach, a coached client and/or coaching yourself at once, a sub-tab bar lets you switch between those views, and within ''My Coach'' you move between Messages, Nutrition and Check-in.', '["Switch between the ''Myself'', ''My Clients'' and ''My Coach'' views", "Move between Messages, Nutrition and Check-in tabs on your coach''s side"]'::jsonb, 10),
('coachCoach', 'Client roster and live status', 'coach', 'See everyone you coach in one list, each card showing at a glance who is training right now, who owes a check-in, and who has unread messages.', '["Open the list of all your active clients", "See a pulsing ''training now'' dot when a client is mid-workout", "See status badges for Sick, Deload or Vacation", "See ''check-in due'' or ''check-in submitted'' labels per client", "See an unread-message count on each client", "Tap a client to open their full detail view"]'::jsonb, 0),
('coachCoach', 'Invite and manage clients', 'coach', 'Add new clients by email and control your roster, with clear errors up front and a confirmation before you cut anyone off.', '["Enter a client''s email and send a coaching invite", "See clear errors (no such user, already coached, already invited, can''t coach yourself)", "See each client''s pending or active status", "End an active coaching relationship (with confirmation)", "Cancel an invite that is still pending"]'::jsonb, 1),
('coachCoach', 'Client overview and progress', 'coach', 'Open a client''s Overview to see their adherence, volume and session trends at a glance, plus what they are set to train today and how their program is progressing.', '["See overall adherence, average volume per cycle and session count", "Tap a stat to open its trend chart (adherence, rolling volume, sessions per week)", "Preview today''s planned workout with suggested weights, or the completed session", "Read a week-by-week adherence table", "See the active plan and program status (5/3/1 cycle or mesocycle week and RIR)", "Review recent sessions and the sick, deload and vacation history"]'::jsonb, 2),
('coachCoach', 'Watch a client train live', 'coach', 'When a client is mid-workout, a pulsing banner lets you drop into a live spectator view and follow their session set by set.', '["Spot the live ''training now, tap to watch'' banner", "Open the live spectator view of the session", "Follow their sets as they log them"]'::jsonb, 3),
('coachCoach', 'Browse a client''s sessions and cardio', 'coach', 'Scroll a client''s completed workouts and cardio logs, and open any session for a full breakdown of every set against its plan target.', '["Scroll completed workouts or switch to the cardio log list", "Filter workouts by training day", "Open a session for volume, sets, duration, feel and set-versus-target detail", "See sets flagged as improvements or declines, with intensity-technique badges", "Tap an exercise for its history chart and toggle weight or reps", "See cardio entries with duration, distance, effort and pace feeling"]'::jsonb, 4),
('coachCoach', 'Review a client''s daily health', 'coach', 'Read a client''s daily health tracking inside their profile, with the same day, week and trend cards they see plus a table of weekly averages.', '["Browse the client''s logged days on the date strip", "See weight, steps, macros, water, cardio, adherence and glucose", "Read weekly averages for the last 8 weeks", "See client weights in the client''s own unit", "Reorder the cards to your own preference"]'::jsonb, 5),
('coachCoach', 'Review client check-ins and trends', 'coach', 'Read every weekly check-in a client submits with all answers laid out, and track how each metric is moving with sparklines and full-screen charts.', '["Expand each weekly check-in to see all responses", "See week-over-week deltas for weight, steps, cardio and pace", "Compare against a ''planned average'' macro row from the targets you set", "Still see answers to fields you later removed, under an ''Additional'' block", "View a trend card with sparkline and latest-versus-previous change per metric", "Tap any metric for a full-screen line chart of its history"]'::jsonb, 6),
('coachCoach', 'Pause or request client check-ins', 'coach', 'Control each client''s check-in cadence: pause or re-enable their weekly check-in, and nudge anyone whose report is due, with the client messaged automatically.', '["Toggle a client''s check-ins on or off (auto-messages them the change)", "Send a check-in reminder to a client", "Dismiss the ''check-in submitted'' marker once reviewed"]'::jsonb, 7),
('coachCoach', 'Customize the check-in form', 'coach', 'Build the exact weekly check-in you want a client to fill in, with your own sections, field types and rules, and preview it before they ever see it.', '["Add, edit, remove and drag-reorder sections and fields", "Pick a field type (text, integer, decimal, stepper scale or multiple choice) with label, width, required and hint", "Set a trend direction (higher or lower is better) and pick an icon", "Add a unit suffix, including one that auto-switches kg/lbs per client", "Turn on ''track daily in health log'' so a field is logged daily and rolled into the check-in", "Preview the client form, the card you receive and 20 weeks of sample trends"]'::jsonb, 8),
('coachCoach', 'Save, template and roll out check-in forms', 'coach', 'Reuse and distribute your check-in forms: keep named templates for different phases and choose whether an edit applies to one client or becomes everyone''s default.', '["Save the form as an override for one client", "Save the form as the new default for all clients", "Save up to 5 named templates (a cutting form, a bulking form)", "Load, update or delete a saved template", "Snapshot the current form before replacing everyone''s", "Reset back to the built-in default form"]'::jsonb, 9),
('coachCoach', 'Export check-ins and progress', 'both', 'Share a client''s check-in or their overall progress as text or an image, handy for sending elsewhere or keeping a record.', '["Export a single check-in as formatted text to share or copy", "Export a single check-in as a PNG image", "Export all trend charts as one combined progress image"]'::jsonb, 10),
('coachCoach', 'Message clients and leave session notes', 'coach', 'Stay in touch through threaded conversations with each client, and attach feedback to a specific workout that lands in their messages.', '["Send and read messages in a client''s thread", "Attach a note to a specific session for the client to read", "See unread-message counts per client", "Get a banner for new coaching messages and tap to jump in", "Delete a note you sent"]'::jsonb, 11),
('coachCoach', 'Build and manage a client''s training plans', 'coach', 'Create, edit and activate a client''s training plans remotely, and every time you change their active plan the app tells them exactly what changed.', '["Build a new plan for the client with the guided builder", "Edit any of the client''s existing plans", "Activate a plan (with confirmation), which notifies the client", "Auto-send a summary of exactly what changed when you save the active plan", "Import a plan from a JSON file or export one to JSON"]'::jsonb, 12),
('coachCoach', 'Set client macros', 'coach', 'Prescribe separate training-day and rest-day nutrition targets with calories worked out for you, and the client is messaged the new numbers automatically.', '["Enter training-day protein, carbs and fat (calories auto-calculated)", "Enter rest-day protein, carbs and fat separately", "Save to auto-message the client their new targets", "Review the full history of macro changes with timestamps"]'::jsonb, 13),
('settings', 'Auto-end idle session', 'user', 'Control how long an open workout can sit idle before it is ended for you.', '["Set the inactivity timeout from 15 to 480 minutes", "Empty sessions with no sets are dropped automatically"]'::jsonb, 0),
('settings', 'Themes, accent colors & week view', 'user', 'Make the app yours with a dark, true-black OLED or light theme, ten accent colors, and an optional weekly overview when your schedule runs in cycle mode.', '["Switch between Dark, OLED black and Light themes", "Pick from ten accent colors that recolor the whole app instantly", "Toggle the weekly overview in cycle mode"]'::jsonb, 1),
('settings', 'Units & display preferences', 'user', 'Choose whether weights and distances show in metric, imperial or a mix, and fine-tune small workout-display behaviours.', '["Pick Metric (kg/km), Imperial (lbs/mi) or Mixed units", "Toggle whether warmup sets show in the workout summary", "Toggle the regression (backward-step) indicator", "Toggle carrying your last weight down to the next set"]'::jsonb, 2),
('settings', 'Equipment & plate setup', 'user', 'Tell the app about your gym''s gear so weight steps and the plate calculator match what you actually load.', '["Set the weight increment and max load per equipment type", "Enter your plate inventory in kg and lbs", "Set how long before an idle session auto-ends"]'::jsonb, 3),
('settings', 'Push notifications', 'user', 'Turn on native push for this device to receive rest-timer, coaching and support alerts, with a verified opt-in so nothing stays half-on.', '["Enable push for this device and confirm with a 6-digit code", "Receive rest-timer, coaching and support alerts", "Send a test notification (now, in 10s or in 30s) to confirm it arrives", "On iOS, install Zane as an app first"]'::jsonb, 4),
('settings', 'Pushover (advanced push)', 'user', 'Route rest-timer alerts through the Pushover app instead of browser push, so they arrive even when the app is not installed.', '["Enable Pushover and verify your user key with a 6-digit code", "Send a test rest timer (now, in 10s or in 30s)", "Disable Pushover to return to browser push"]'::jsonb, 5),
('settings', 'Training-day reminders', 'user', 'Get a push reminder on days you are scheduled to train, at a time you choose, so you never miss a session.', '["Turn on reminders for training days", "Set the time the reminder fires", "See when the next reminder is due", "Jump straight to push setup if it is not enabled yet"]'::jsonb, 6),
('settings', 'Backup & restore', 'user', 'Export your entire history to a JSON file and restore it later, covering training, health, cardio and settings.', '["Export a full JSON backup to a downloaded file", "Restore from a backup file, choosing its source weight unit", "Back up current data before an import and confirm the replace warning", "Watch import progress as it runs"]'::jsonb, 7),
('settings', 'Delete all data', 'user', 'Permanently erase every workout, plan and log on your account, then sign out.', '["Type the required confirmation phrase to erase everything", "Understand the deletion cannot be undone"]'::jsonb, 8),
('settings', 'Clear cache & reload', 'user', 'Force the app to drop its local cache and reload when something looks stuck, and check which version you are running.', '["Clear the cache and reload the app", "See the current app version in the footer"]'::jsonb, 9);
